import { Component, Element, h, Prop } from '@stencil/core';
import { generateRandId } from '../../../utils/utils';

@Component({
  tag: 'wdpr-standalone-results-list-group',
  shadow: true,
})
export class WdprStandaloneResultsListGroup {
  private _internalId: string;

  @Element() el: HTMLWdprStandaloneResultsListGroupElement;

  @Prop() header: string;

  componentWillLoad() {
    this._internalId = `wdpr-standalone-results-list-group-${generateRandId()}`;
  }

  render() {
    return (
      <div class="flex flex-col gap-y-100">
        {this.header && (
          <span class="body-medium text-text-heading" id={`${this._internalId}-header`}>
            {this.header}
          </span>
        )}
        <ul key={this._internalId} class="flex flex-col gap-y-100" aria-labelledby={`${this.header ? `${this._internalId}-header` : ''}`}>
          <slot />
        </ul>
      </div>
    );
  }
}
